custom_css:
body{background:#fff;color:#171717;}
.page_content,.page-content,.page-content-wrapper{background:#fff;}
[data-doctype='Web Form'] .page-content-wrapper .container .page_content{max-width:none;width:100%;padding:0 20px 72px;}
.web-form-container,.page-card{max-width:1200px;margin:0 auto;padding:0;background:transparent;border:0;box-shadow:none;}
.web-form-header{padding:64px 0 28px;border:0;}
.web-form-header::before{content:'MASTER AGREEMENT';display:block;margin:0 0 14px;color:#0f5132;font-size:13px;font-weight:700;letter-spacing:.08em;line-height:1.2;text-transform:uppercase;}
.web-form-header h1{margin:0;max-width:760px;color:#171717;font-size:clamp(2.4rem,5vw,4.5rem);font-weight:700;line-height:1.03;letter-spacing:-.03em;}
.web-form-header .introduction,.web-form-header p{margin:18px 0 0;max-width:840px;color:#525252;font-size:17px;font-weight:500;line-height:1.65;}
.web-form-wrapper,.web-form-body,.form-page{background:#fff;}
.form-page{border:1px solid #e7e7e7;border-radius:28px;padding:30px;}
.section-head{margin:0 0 18px;padding-top:26px;border-top:1px solid #e7e7e7;color:#171717;font-size:30px;font-weight:700;line-height:1.15;letter-spacing:-.02em;}
.form-page .section-head:first-child{padding-top:0;border-top:0;}
.web-form-wrapper .row{margin-left:-10px;margin-right:-10px;}
.web-form-wrapper [class*='col-']{padding-left:10px;padding-right:10px;}
.form-group{margin-bottom:20px;}
.control-label,.web-form-label,label{margin-bottom:8px;color:#171717;font-size:14px;font-weight:700;line-height:1.2;}
.control-input{background:transparent;border:0;padding:0;box-shadow:none;}
.form-control,.input-with-feedback,.ql-editor{min-height:56px;width:100%;padding:14px 16px;border:1px solid #d7d7d7;border-radius:16px;background:#fff;color:#171717;box-shadow:none;box-sizing:border-box;}
.frappe-control[data-fieldtype='Select'] .control-input{position:relative;}
.frappe-control[data-fieldtype='Select'] .control-input .select-icon{top:50%;right:16px;transform:translateY(-50%);padding:0;width:16px;height:16px;display:flex;align-items:center;justify-content:center;}
.frappe-control[data-fieldtype='Select'] .control-input .select-icon .icon,.frappe-control[data-fieldtype='Select'] .control-input .select-icon .es-icon{width:16px;height:16px;display:block;}
.frappe-control[data-fieldtype='Select'] select.form-control{padding-right:44px;}
textarea.form-control,.ql-editor{min-height:220px;}
.form-control:focus,.input-with-feedback:focus,.ql-editor:focus{border-color:#171717;outline:none;box-shadow:rgba(23,23,23,.08) 0 0 0 4px;}
.ql-toolbar,.ql-container{border-color:#d7d7d7;}
.ql-toolbar{border-radius:16px 16px 0 0;background:#fff;}
.ql-container{border-radius:0 0 16px 16px;}
.web-form-actions,.web-form-footer,.form-submit-container{display:flex;flex-direction:column;align-items:flex-start;gap:12px;margin-top:10px;}
.discard-btn,.web-form-actions .discard-btn,.web-form-footer .discard-btn{display:none !important;}
.submit-btn.btn,.btn-primary.submit-btn,.web-form-actions .submit-btn,.web-form-footer .submit-btn{appearance:none;border:0;border-radius:16px;background:#171717 !important;color:#fff !important;cursor:pointer;font-size:15px;font-weight:700;line-height:1.1;padding:16px 20px;min-height:52px;box-shadow:none;}
.submit-btn.btn:hover,.submit-btn.btn:focus,.btn-primary.submit-btn:hover,.btn-primary.submit-btn:focus,.web-form-actions .submit-btn:hover,.web-form-actions .submit-btn:focus,.web-form-footer .submit-btn:hover,.web-form-footer .submit-btn:focus{background:#303030 !important;color:#fff !important;}
.text-muted,.help-box,small,.small{color:#737373 !important;font-size:13px;line-height:1.6;}
@media (max-width:768px){[data-doctype='Web Form'] .page-content-wrapper .container .page_content{padding:0 12px 40px;}[data-doctype='Web Form'] .page-content-wrapper .container .page_content .web-form .web-form-wrapper .form-column{padding-left:0;padding-right:0;}.web-form-wrapper .row{margin-left:0;margin-right:0;}.web-form-header{padding:36px 0 16px;}.web-form-header .introduction,.web-form-header p{margin-top:14px;font-size:15px;line-height:1.55;}.form-page{padding:16px;border-radius:22px;}.section-head{padding-top:20px;font-size:24px;}}

